def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    skewness = np.mean((positive_bins - avg_capacity) ** 3) / (np.std(positive_bins) ** 3 + 1e-9) if positive_bins.size > 0 else 0
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity * 1.1:
            priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else 0
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = ((1 - ratio) ** 7) * 1.5 + 0.3
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-ratio * 20) + 0.1
        elif 0.4 < ratio <= 0.7:
            temp_sum = 0.0
            for k in range(1, 13):
                coefficient = ((-1) ** (k+1)) * (ratio ** (k + 3)) / (k * 1.05)
                temp_sum += coefficient
            score = abs(temp_sum) + 0.07
        else:
            temp_sum = 0.0
            for p in range(1, 15):
                w = 1 / (p ** 1.5)
                temp_sum += ((-1) ** p) * (ratio ** (p + 2)) * w
            score = abs(temp_sum) + 0.1
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        weighted_diff_sum = 0.0
        for offset in range(1, min(10, n)):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            weight = 1 / (offset ** 2.2)
            local_influence = 0.0
            local_weight_count = 0
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + variance:
                        influence *= 1.15 + 0.05 * skewness
                    elif neighbor_capacity < avg_capacity - variance:
                        influence *= 0.85 - 0.03 * skewness
                    local_influence += influence
                    local_weight_count += weight
                    weighted_diff_sum += norm_diff * weight * neighbor_capacity
            if local_weight_count > 0:
                neighbors_influence += local_influence / local_weight_count
                neighbors_weights_sum += 1.0
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        else:
            neighbors_influence = 0.0
        cap_factor = (capacity ** 0.65) + (avg_capacity ** 0.35) + 0.01
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 3.2) * 0.45 + 0.05 * (variance + skewness)
        elif capacity > item * 1.8:
            penalty = 0.07 - 0.02 * skewness
        else:
            penalty = 0.0
        if i % 5 == 0:
            score *= 0.85 + 0.05 * (skewness if skewness > 0 else 0)
            neighbors_influence *= 1.25 - 0.1 * abs(skewness)
            penalty *= 1.05 + 0.02 * abs(skewness)
        elif i % 3 == 0:
            score *= 1.15 - 0.07 * (skewness if skewness < 0 else 0)
            neighbors_influence *= 0.85 + 0.12 * abs(skewness)
            penalty *= 0.9 - 0.03 * skewness
        else:
            score *= 0.9 + 0.04 * (weighted_diff_sum / (cap_factor + 1e-6))
        if ratio < 0.15:
            penalty += 0.15 * (1 - ratio) ** 2
        priority = score + neighbors_influence / cap_factor + penalty
        if priority < 0:
            priority = 0
        if capacity < item * 0.7 and ratio < 0.9:
            priority *= 1.3
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7 + np.sqrt(avg_capacity) * 0.1
    return priorities
